OUTPUT_PATH = BASE / "diploma_snappix_expanded.docx"
ASSETS_DIR = BASE / "diploma_assets"


def clean(value: str) -> str:
    return " ".join((value or "").split())


def insert_para_after(paragraph: Paragraph, text: str = "", style: str | None = None) -> Paragraph:
    new_p = OxmlElement("w:p")
    paragraph._p.addnext(new_p)
    new_paragraph = Paragraph(new_p, paragraph._parent)
    if style:
        new_paragraph.style = style
    if text:
        new_paragraph.add_run(text)
    return new_paragraph


def find_para(doc: Document, startswith: str) -> Paragraph:
    for paragraph in doc.paragraphs:
        if clean(paragraph.text).startswith(startswith):
            return paragraph
    raise ValueError(f"Paragraph not found: {startswith}")


def insert_after(anchor: Paragraph, items: list) -> Paragraph:
    paragraph = anchor
    for item in items:
        if isinstance(item, tuple) and item[0] == "heading":
            paragraph = insert_para_after(paragraph, item[2], f"Heading {item[1]}")
        elif isinstance(item, tuple) and item[0] == "image":
            paragraph = insert_para_after(paragraph, "", "normal")
            paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
            paragraph.add_run().add_picture(str(item[1]), width=Inches(item[2]))
        elif isinstance(item, tuple) and item[0] == "caption":
            paragraph = insert_para_after(paragraph, item[1], "normal")
            paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
        else:
            paragraph = insert_para_after(paragraph, item, "normal")
    return paragraph


def replace_para_start(doc: Document, startswith: str, new_text: str) -> None:
    paragraph = find_para(doc, startswith)
    paragraph.text = new_text


def append_unique_row(table, values: tuple[str, ...]) -> None:
    existing = {clean(row.cells[0].text) for row in table.rows}
    if values[0] in existing:
        return
    row = table.add_row()
    for index, value in enumerate(values):
        row.cells[index].text = value


